esqlQuery.esql:
TS metrics-k8sclusterreceiver.otel-*
| STATS restart_rate = MAX(RATE(k8s.container.restarts))
    BY k8s.pod.name, k8s.container.name, k8s.namespace.name
// restart_rate is restarts per second. Any non-zero rate means
// the container is actively restarting. Combined with alert_delay
// of 3 consecutive evaluations, this catches sustained crash loops
// without firing on historical restart counts or one-off restarts.
| WHERE restart_rate > 0
| SORT restart_rate DESC
| KEEP k8s.namespace.name, k8s.pod.name, k8s.container.name, restart_rate
| LIMIT 50
